# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

from flask import Flask, request, jsonify
import redis
import os

app = Flask(__name__)

redis_nodes = [
    {'host': 'redis-node-1', 'port': 6379},
    {'host': 'redis-node-2', 'port': 6379},
    {'host': 'redis-node-3', 'port': 6379}
]

redis_cluster = redis.StrictRedisCluster(startup_nodes=redis_nodes)

@app.route('/store_token', methods=['POST'])
def store_token():
    data = request.json
    user_id = data.get('user_id')
    token = data.get('token')
    ttl = data.get('ttl', 3600)  # Default TTL in seconds

    if not user_id or not token:
        return jsonify({'error': 'user_id and token are required'}), 400

    redis_cluster.setex(f"user:{user_id}:session_token", ttl, token)
    return jsonify({'message': 'Token stored successfully'}), 200

@app.route('/get_token/<user_id>', methods=['GET'])
def get_token(user_id):
    token = redis_cluster.get(f"user:{user_id}:session_token")

    if token is None:
        return jsonify({'error': 'Token not found or expired'}), 404

    return jsonify({'token': token.decode('utf-8')}), 200

@app.route('/delete_token/<user_id>', methods=['DELETE'])
def delete_token(user_id):
    result = redis_cluster.delete(f"user:{user_id}:session_token")

    if result == 0:
        return jsonify({'error': 'Token not found'}), 404

    return jsonify({'message': 'Token deleted successfully'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))